import{_ as e,o as a,c as d,ag as r}from"./chunks/framework.DTiDeF2Q.js";const b=JSON.parse('{"title":"Интерактивные псевдонимы | Dotfiles (RU)","titleTemplate":":title","description":"Псевдонимы оболочки, добавляющие интерактивные подтверждения перед деструктивными операциями, такими как rm, mv и cp. Предотвратите случайное удаление файлов.","frontmatter":{"title":"Интерактивные псевдонимы | Dotfiles","description":"Псевдонимы оболочки, добавляющие интерактивные подтверждения перед деструктивными операциями, такими как rm, mv и cp. Предотвратите случайное удаление файлов.","lang":"ru-RU","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Интерактивные псевдонимы preview","canonical":"/ru/aliases/interactive/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Интерактивные псевдонимы","pageType":"docs","schemaType":"WebPage","metaTitle":"Интерактивные псевдонимы - Dotfiles (RU)","permalink":"/ru/aliases/interactive/","sidebar":true,"meta":[{"name":"keywords","content":"interactive aliases, shell safety, rm confirmation, cp interactive, mv prompt, dotfiles, bash aliases"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Интерактивные псевдонимы - Dotfiles"},{"name":"twitter:description","content":"Псевдонимы оболочки, добавляющие интерактивные подтверждения перед деструктивными операциями, такими как rm, mv и cp."},{"name":"og:title","content":"Интерактивные псевдонимы - Dotfiles"},{"name":"og:description","content":"Псевдонимы оболочки, добавляющие интерактивные подтверждения перед деструктивными операциями, такими как rm, mv и cp."},{"name":"og:image:alt","content":"Dotfiles - Простой дизайн для вашей жизни в командной оболочке"},{"name":"og:locale","content":"ru_RU"}]},"headers":[],"relativePath":"ru/aliases/interactive/index.md","filePath":"ru/aliases/interactive/index.md","lastUpdated":1773010926000}'),o={name:"ru/aliases/interactive/index.md"};function i(c,t,n,l,s,h){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="интерактивные-псевдонимы" tabindex="-1">Интерактивные псевдонимы <a class="header-anchor" href="#интерактивные-псевдонимы" aria-label="Permalink to &quot;Интерактивные псевдонимы&quot;">​</a></h1><p>Безопасные команды оболочки с запросом подтверждения перед деструктивными операциями.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Баннер Dotfiles"></p><h2 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h2><p>Интерактивные псевдонимы добавляют запросы подтверждения к распространённым командам оболочки, которые могут необратимо изменить или удалить файлы. Определённые в <code>interactive.aliases.sh</code> и автоматически загружаемые chezmoi, эти псевдонимы помогают предотвратить случайную потерю данных, требуя подтверждения пользователя перед выполнением потенциально деструктивных операций.</p><h2 id="справочник" tabindex="-1">Справочник <a class="header-anchor" href="#справочник" aria-label="Permalink to &quot;Справочник&quot;">​</a></h2><h3 id="операции-с-фаилами" tabindex="-1">Операции с файлами <a class="header-anchor" href="#операции-с-фаилами" aria-label="Permalink to &quot;Операции с файлами&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>cp</code></td><td>Копировать файлы и директории интерактивно с подробным выводом. Запрашивает подтверждение перед перезаписью.</td></tr><tr><td><code>mv</code></td><td>Переместить или переименовать файлы интерактивно с подробным выводом. Запрашивает подтверждение перед перезаписью.</td></tr><tr><td><code>ln</code></td><td>Создать символические ссылки интерактивно с подробным выводом. Запрашивает подтверждение перед перезаписью.</td></tr></tbody></table><h3 id="удаление-фаилов" tabindex="-1">Удаление файлов <a class="header-anchor" href="#удаление-фаилов" aria-label="Permalink to &quot;Удаление файлов&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>rm</code></td><td>Удалить файлы или директории интерактивно с подробным выводом. Запрашивает подтверждение перед каждым удалением.</td></tr><tr><td><code>del</code></td><td>Удалить файлы или директории интерактивно и рекурсивно с подробным выводом. Запрашивает подтверждение.</td></tr><tr><td><code>zap</code></td><td>Псевдоним для <code>rm</code>. Удаляет файлы или директории интерактивно с подробным выводом.</td></tr></tbody></table><h3 id="управление-корзинои" tabindex="-1">Управление корзиной <a class="header-anchor" href="#управление-корзинои" aria-label="Permalink to &quot;Управление корзиной&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>bin</code></td><td>Удалить все файлы в директории корзины (<code>~/.Trash</code>) принудительно и рекурсивно.</td></tr></tbody></table><h3 id="права-доступа-и-утилиты" tabindex="-1">Права доступа и утилиты <a class="header-anchor" href="#права-доступа-и-утилиты" aria-label="Permalink to &quot;Права доступа и утилиты&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>chmod</code></td><td>Изменить права доступа к файлу или директории с подробным выводом.</td></tr><tr><td><code>chown</code></td><td>Изменить владельца и группу файла или директории с подробным выводом.</td></tr><tr><td><code>diff</code></td><td>Сравнить и показать различия между двумя файлами в унифицированном формате.</td></tr><tr><td><code>grep</code></td><td>Искать шаблон в файлах или выводе, показывая номера строк без учёта регистра.</td></tr><tr><td><code>mkdir</code></td><td>Создать новую директорию с родительскими директориями по необходимости и подробным выводом.</td></tr></tbody></table>',14)])])}const p=e(o,[["render",i]]);export{b as __pageData,p as default};
